1	// WORKSTATE 상태 전이의 유일한 writer. 낙관적 동시성·멱등 전이-ID·canonical 검증·사전조건 검사를 강제한다.
2	using System.Security.Cryptography;
3	using System.Text;
4	using System.Text.Encodings.Web;
5	using System.Text.Json;
6	using System.Text.Json.Nodes;
7	using System.Text.RegularExpressions;
8	
9	internal static class StateApplierCli
10	{
11	    private static readonly JsonSerializerOptions WriteOptions = new()
12	    {
13	        WriteIndented = true,
14	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
15	    };
16	
17	    private static readonly HashSet<string> ValidStatuses = new(StringComparer.OrdinalIgnoreCase)
18	    {
19	        "waiting", "in_progress", "verifying", "completed", "blocked",
20	    };
21	
22	    // nextActions 필수 status 목록(completed 제외).
23	    private static readonly HashSet<string> NextActionsRequired = new(StringComparer.OrdinalIgnoreCase)
24	    {
25	        "waiting", "in_progress", "verifying", "blocked",
26	    };
27	
28	    // CLI 인수를 담는 불변 레코드.
29	    private record ApplierOptions(
30	        string TransitionId,
31	        string ExpectedSha256,
32	        string RequestPath,
33	        string? VerdictPath,
34	        string? HumanDecisionPath);
35	
36	    // state-transition 진입점. exit 0=성공, 1=검증 실패, 2=치명 오류.
37	    internal static int Run(string[] args)
38	    {
39	        var opts = ParseArgs(args);
40	        if (opts is null)
41	        {
42	            Console.Error.WriteLine("{\"error\":\"--transition-id, --expected-workstate-sha256, --request 가 모두 필요합니다\"}");
43	            return 2;
44	        }
45	
46	        try
47	        {
48	            var root = GitTools.FindRepoRoot();
49	            var workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
50	            if (!File.Exists(workstatePath))
51	            {
52	                WriteError("WORKSTATE.json not found");
53	                return 2;
54	            }
55	
56	            var raw = File.ReadAllText(workstatePath, new UTF8Encoding(false));
57	            var workstate = JsonNode.Parse(raw)?.AsObject();
58	            if (workstate is null)
59	            {
60	                WriteError("WORKSTATE.json is not a valid JSON object");
61	                return 2;
62	            }
63	
64	            // Step 1: 낙관적 동시성 — sha256 불일치 시 쓰지 않는다.
65	            var currentSha = ComputeSha256(raw);
66	            if (!string.Equals(currentSha, opts.ExpectedSha256, StringComparison.OrdinalIgnoreCase))
67	                return Fail(1, opts.TransitionId, "sha256-mismatch",
68	                    $"expected={opts.ExpectedSha256[..Math.Min(16, opts.ExpectedSha256.Length)]}... " +
69	                    $"actual={currentSha[..Math.Min(16, currentSha.Length)]}...");
70	
71	            // Step 2: 멱등 — 같은 transition-id는 한 번만 적용한다.
72	            if (IsAlreadyApplied(workstate, opts.TransitionId))
73	                return ReportIdempotent(opts.TransitionId);
74	
75	            var logPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
76	            return ApplyAndVerify(workstatePath, logPath, workstate, opts, root);
77	        }
78	        catch (Exception ex)
79	        {
80	            Console.Error.WriteLine($"{{\"error\":\"state-transition 실패: {ex.Message}\"}}");
81	            return 2;
82	        }
83	    }
84	
85	    // request 검증, candidate 구성, atomic replace, projection, handoff-integrity를 순서대로 실행한다.
86	    private static int ApplyAndVerify(
87	        string workstatePath, string logPath, JsonObject workstate,
88	        ApplierOptions opts, string root)
89	    {
90	        if (!File.Exists(opts.RequestPath))
91	        {
92	            WriteError($"request file not found: {opts.RequestPath}");
93	            return 2;
94	        }
95	
96	        var request = JsonNode.Parse(File.ReadAllText(opts.RequestPath))?.AsObject();
97	        if (request is null)
98	        {
99	            WriteError("request JSON은 JSON 객체여야 한다");
100	            return 2;
101	        }
102	
103	        // Step 3-4: 입력 검증
104	        var validErr = ValidateRequest(request, opts, workstate, root);
105	        if (validErr is not null)
106	            return Fail(1, opts.TransitionId, "validation-failed", validErr);
107	
108	        // Step 5-6: candidate 구성 후 임시 파일에 쓴다.
109	        var candidate = BuildCandidate(workstate, request, opts);
110	        var tmpPath = workstatePath + ".stateapplier.tmp";
111	        File.WriteAllText(tmpPath, candidate.ToJsonString(WriteOptions), new UTF8Encoding(false));
112	
113	        // Step 7: candidate 재검증 (임시 파일에서 재로드).
114	        var candidateCheck = JsonNode.Parse(File.ReadAllText(tmpPath))?.AsObject();
115	        var recheckErr = candidateCheck is null ? "임시 파일 파싱 실패" : ValidateCandidate(candidateCheck);
116	        if (recheckErr is not null)
117	        {
118	            File.Delete(tmpPath);
119	            return Fail(1, opts.TransitionId, "candidate-invalid", recheckErr);
120	        }
121	
122	        // Step 8: atomic replace — 이 시점부터 WORKSTATE가 새 상태다.
123	        File.Move(tmpPath, workstatePath, overwrite: true);
124	
125	        // Step 9: projection 실행 (RUNTIME-INDEX.md, HANDOFF.md 재생성).
126	        var projExit = ProjectionCli.Run(["projection"]);
127	        if (projExit != 0)
128	        {
129	            AppendApplierLog(logPath, opts.TransitionId, "projection-failed", projExit);
130	            Console.Error.WriteLine(PostApplyError(opts.TransitionId, "projection-failed", projExit, true, false));
131	            return 1;
132	        }
133	
134	        // Step 10: handoff-integrity 실행.
135	        var integrityExit = HandoffIntegrityCli.Run(["handoff-integrity"]);
136	        if (integrityExit != 0)
137	        {
138	            AppendApplierLog(logPath, opts.TransitionId, $"handoff-integrity-failed exit={integrityExit}", integrityExit);
139	            Console.Error.WriteLine(PostApplyError(opts.TransitionId, $"handoff-integrity exit={integrityExit}", integrityExit, true, true));
140	            return 1;
141	        }
142	
143	        var newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false)));
144	        AppendApplierLog(logPath, opts.TransitionId, "ok", 0);
145	        Console.WriteLine(new JsonObject
146	        {
147	            ["ok"] = true,
148	            ["transitionId"] = opts.TransitionId,
149	            ["previousStatus"] = workstate["status"]?.ToString(),
150	            ["newStatus"] = candidate["status"]?.ToString(),
151	            ["workstateSha256"] = newSha,
152	        }.ToJsonString(WriteOptions));
153	        return 0;
154	    }
155	
156	    // request JSON의 canonical ID 패턴, status enum, 사전조건(blocked/nextActions/verdict/human-decision)을 검증한다.
157	    private static string? ValidateRequest(JsonObject request, ApplierOptions opts, JsonObject current, string root)
158	    {
159	        if (request["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
160	            return $"phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
161	
162	        if (request["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
163	            return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
164	
165	        if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
166	            return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
167	
168	        var newStatus = request["status"]?.ToString() ?? current["status"]?.ToString() ?? "";
169	        if (!ValidStatuses.Contains(newStatus))
170	            return $"status '{newStatus}'는 허용 목록(waiting|in_progress|verifying|completed|blocked)에 없습니다";
171	
172	        var newBlockers = request["blockers"] as JsonArray ?? current["blockers"] as JsonArray ?? new JsonArray();
173	        var newNext = request["nextActions"] as JsonArray ?? current["nextActions"] as JsonArray ?? new JsonArray();
174	
175	        // Rule 4: blocked → blockers 비어있으면 실패.
176	        if (string.Equals(newStatus, "blocked", StringComparison.OrdinalIgnoreCase) && newBlockers.Count == 0)
177	            return "status=blocked인데 blockers가 비어있습니다";
178	
179	        // Rule 5: non-terminal → nextActions 비어있으면 실패 (독립 재개 FAIL 방어선).
180	        if (NextActionsRequired.Contains(newStatus) && newNext.Count == 0)
181	            return $"status={newStatus}인데 nextActions가 비어있습니다 — 독립 재개가 실패하는 지점입니다";
182	
183	        // Rule 6: completed → 독립 검증 PASS 필수.
184	        if (string.Equals(newStatus, "completed", StringComparison.OrdinalIgnoreCase))
185	        {
186	            var verdictErr = ValidateVerdict(opts.VerdictPath);
187	            if (verdictErr is not null) return verdictErr;
188	        }
189	
190	        // Rule 7: Phase gate → 사람 결정 필수.
191	        var curPhase = current["phaseId"]?.ToString();
192	        var newPhase = request["phaseId"]?.ToString();
193	        if (newPhase is not null && !string.Equals(newPhase, curPhase, StringComparison.OrdinalIgnoreCase))
194	        {
195	            var gateErr = ValidateHumanDecision(opts.HumanDecisionPath, curPhase, newPhase);
196	            if (gateErr is not null) return gateErr;
197	        }
198	
199	        return null;
200	    }
201	
202	    // verdict 파일이 verificationPassed=true, exitCode=0인지 검증한다.
203	    private static string? ValidateVerdict(string? verdictPath)
204	    {
205	        if (string.IsNullOrWhiteSpace(verdictPath))
206	            return "status=completed 전이에는 --verdict 파일이 필요합니다";
207	        if (!File.Exists(verdictPath))
208	            return $"verdict file not found: {verdictPath}";
209	        var v = JsonNode.Parse(File.ReadAllText(verdictPath))?.AsObject();
210	        if (v is null) return "verdict JSON이 유효하지 않습니다";
211	        var passed = v["verificationPassed"]?.GetValue<bool>() ?? false;
212	        var exitCode = v["exitCode"]?.GetValue<int>() ?? -1;
213	        return (!passed || exitCode != 0) ? $"verdict: verificationPassed={passed}, exitCode={exitCode} — PASS가 아닙니다" : null;
214	    }
215	
216	    // human-decision 파일이 approved=true인지 검증한다.
217	    private static string? ValidateHumanDecision(string? decPath, string? from, string? to)
218	    {
219	        if (string.IsNullOrWhiteSpace(decPath))
220	            return $"Phase 전이({from} → {to})에는 --human-decision 파일이 필요합니다";
221	        if (!File.Exists(decPath))
222	            return $"human-decision file not found: {decPath}";
223	        var d = JsonNode.Parse(File.ReadAllText(decPath))?.AsObject();
224	        if (d is null) return "human-decision JSON이 유효하지 않습니다";
225	        var approved = d["approved"]?.GetValue<bool>() ?? false;
226	        return !approved ? $"Phase 전이가 사람에게 승인되지 않았습니다(approved={approved})" : null;
227	    }
228	
229	    // request 필드를 current WORKSTATE에 병합해 candidate를 만들고 appliedTransitions에 기록한다.
230	    private static JsonObject BuildCandidate(JsonObject current, JsonObject request, ApplierOptions opts)
231	    {
232	        var candidate = JsonNode.Parse(current.ToJsonString(WriteOptions))!.AsObject()!;
233	
234	        foreach (var key in new[] { "phaseId", "wpId", "diId", "status", "blockers", "nextActions", "updatedBy", "notes" })
235	        {
236	            if (request[key] is JsonNode node)
237	                candidate[key] = node.DeepClone();
238	        }
239	
240	        candidate["updatedAt"] = DateTime.UtcNow.ToString("yyyy-MM-dd");
241	
242	        if (candidate["appliedTransitions"] is not JsonArray applied)
243	        {
244	            applied = new JsonArray();
245	            candidate["appliedTransitions"] = applied;
246	        }
247	
248	        applied.Add(new JsonObject
249	        {
250	            ["id"] = opts.TransitionId,
251	            ["appliedAt"] = DateTime.UtcNow.ToString("o"),
252	        });
253	
254	        return candidate;
255	    }
256	
257	    // candidate WORKSTATE의 사후 조건(status enum, blocked→blockers, non-terminal→nextActions)을 검증한다.
258	    private static string? ValidateCandidate(JsonObject candidate)
259	    {
260	        var status = candidate["status"]?.ToString() ?? "";
261	        if (!ValidStatuses.Contains(status))
262	            return $"candidate status '{status}'가 유효하지 않습니다";
263	
264	        var blockers = candidate["blockers"] as JsonArray;
265	        if (string.Equals(status, "blocked", StringComparison.OrdinalIgnoreCase) && (blockers is null || blockers.Count == 0))
266	            return "candidate: status=blocked인데 blockers가 비어있습니다";
267	
268	        var nextActions = candidate["nextActions"] as JsonArray;
269	        if (NextActionsRequired.Contains(status) && (nextActions is null || nextActions.Count == 0))
270	            return $"candidate: status={status}인데 nextActions가 비어있습니다";
271	
272	        return null;
273	    }
274	
275	    // CLI 인수를 파싱한다. 필수 인수(transition-id·expected-workstate-sha256·request)가 없으면 null 반환.
276	    private static ApplierOptions? ParseArgs(string[] args)
277	    {
278	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
279	        for (var i = 1; i < args.Length - 1; i++)
280	        {
281	            if (args[i].StartsWith("--", StringComparison.Ordinal))
282	                map[args[i][2..]] = args[i + 1];
283	        }
284	
285	        if (!map.TryGetValue("transition-id", out var tid) || string.IsNullOrWhiteSpace(tid)) return null;
286	        if (!map.TryGetValue("expected-workstate-sha256", out var sha) || string.IsNullOrWhiteSpace(sha)) return null;
287	        if (!map.TryGetValue("request", out var req) || string.IsNullOrWhiteSpace(req)) return null;
288	
289	        map.TryGetValue("verdict", out var verdict);
290	        map.TryGetValue("human-decision", out var humanDec);
291	        return new ApplierOptions(tid, sha, req, verdict, humanDec);
292	    }
293	
294	    // appliedTransitions에서 transition-id 중복 여부를 확인한다.
295	    private static bool IsAlreadyApplied(JsonObject workstate, string transitionId)
296	    {
297	        var applied = workstate["appliedTransitions"] as JsonArray;
298	        if (applied is null) return false;
299	        return applied.OfType<JsonObject>().Any(o =>
300	            string.Equals(o["id"]?.ToString(), transitionId, StringComparison.OrdinalIgnoreCase));
301	    }
302	
303	    // 이미 적용된 transition-id에 대한 idempotent 응답을 출력하고 0을 반환한다.
304	    private static int ReportIdempotent(string transitionId)
305	    {
306	        Console.WriteLine(new JsonObject
307	        {
308	            ["ok"] = true,
309	            ["transitionId"] = transitionId,
310	            ["idempotent"] = true,
311	            ["note"] = "이 transition-id는 이미 적용됐다 — 상태를 바꾸지 않는다",
312	        }.ToJsonString(WriteOptions));
313	        return 0;
314	    }
315	
316	    // post-apply 단계 실패 메시지를 JSON 문자열로 만든다.
317	    private static string PostApplyError(string tid, string failure, int exitCode, bool wsApplied, bool projApplied)
318	    {
319	        var note = projApplied
320	            ? "WORKSTATE와 projection은 갱신됐으나 handoff-integrity가 실패했다"
321	            : "WORKSTATE는 갱신됐으나 projection이 실패했다 — projection을 수동으로 재실행하라";
322	        return new JsonObject
323	        {
324	            ["transitionId"] = tid,
325	            ["phase"] = "post-apply",
326	            ["failure"] = failure,
327	            ["exitCode"] = exitCode,
328	            ["workstateApplied"] = wsApplied,
329	            ["projectionApplied"] = projApplied,
330	            ["note"] = note,
331	        }.ToJsonString();
332	    }
333	
334	    // 전이 결과를 WORKSTATE.applier-log.jsonl에 한 줄 추가한다(append-only).
335	    private static void AppendApplierLog(string logPath, string transitionId, string result, int exitCode)
336	    {
337	        var entry = new JsonObject
338	        {
339	            ["transitionId"] = transitionId,
340	            ["result"] = result,
341	            ["exitCode"] = exitCode,
342	            ["at"] = DateTime.UtcNow.ToString("o"),
343	        };
344	        File.AppendAllText(logPath, entry.ToJsonString() + "\n", new UTF8Encoding(false));
345	    }
346	
347	    // stderr에 JSON 오류 메시지를 출력한다.
348	    private static void WriteError(string message)
349	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
350	
351	    // 실패 결과를 stderr에 출력하고 지정 exit code를 반환한다.
352	    private static int Fail(int exitCode, string transitionId, string reason, string detail)
353	    {
354	        Console.Error.WriteLine(new JsonObject
355	        {
356	            ["ok"] = false,
357	            ["transitionId"] = transitionId,
358	            ["reason"] = reason,
359	            ["detail"] = detail,
360	        }.ToJsonString());
361	        return exitCode;
362	    }
363	
364	    // 문자열의 SHA-256을 소문자 hex로 반환한다.
365	    private static string ComputeSha256(string content)
366	        => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(content))).ToLowerInvariant();
367	}
