1	// WORKSTATE sha256 스탬핑 및 Projection 파일(RUNTIME-INDEX.md, HANDOFF.md) 생성기.
2	using System.Security.Cryptography;
3	using System.Text;
4	using System.Text.Encodings.Web;
5	using System.Text.Json;
6	using System.Text.Json.Nodes;
7	
8	internal static class ProjectionCli
9	{
10	    private static readonly JsonSerializerOptions WriteOptions = new()
11	    {
12	        WriteIndented = true,
13	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
14	    };
15	
16	    private const string GeneratedWarning =
17	        "<!-- GENERATED by 'dotnet run --project server -- projection'. 직접 편집하지 마라 — 다음 실행에서 덮어써진다. 원본은 docs/handoff/WORKSTATE.json 이다. -->";
18	
19	    // Projection 파일은 자기 자신의 해시를 WORKSTATE에 기록하지 않는다(순환 참조 금지).
20	    private static readonly HashSet<string> SelfExcluded = new(StringComparer.OrdinalIgnoreCase)
21	    {
22	        "docs/context/RUNTIME-INDEX.md",
23	        "docs/handoff/HANDOFF.md",
24	    };
25	
26	    // 진입점: WORKSTATE sha256 스탬핑 후 RUNTIME-INDEX.md, HANDOFF.md를 생성한다. exit 0=성공, 2=치명 오류.
27	    internal static int Run(string[] args)
28	    {
29	        try
30	        {
31	            var root = GitTools.FindRepoRoot();
32	            var workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
33	
34	            if (!File.Exists(workstatePath))
35	            {
36	                Console.Error.WriteLine("{\"error\":\"WORKSTATE.json not found\"}");
37	                return 2;
38	            }
39	
40	            var workstate = JsonNode.Parse(File.ReadAllText(workstatePath))?.AsObject();
41	            if (workstate is null)
42	            {
43	                Console.Error.WriteLine("{\"error\":\"WORKSTATE.json is not a JSON object\"}");
44	                return 2;
45	            }
46	
47	            StampHashes(root, workstate);
48	            WriteAtomically(workstatePath, workstate.ToJsonString(WriteOptions));
49	
50	            var runtimeIndexPath = Path.Combine(root, "docs", "context", "RUNTIME-INDEX.md");
51	            Directory.CreateDirectory(Path.GetDirectoryName(runtimeIndexPath)!);
52	            File.WriteAllText(runtimeIndexPath, GenerateRuntimeIndex(workstate), new UTF8Encoding(false));
53	
54	            var handoffPath = Path.Combine(root, "docs", "handoff", "HANDOFF.md");
55	            File.WriteAllText(handoffPath, GenerateHandoff(root, workstate), new UTF8Encoding(false));
56	
57	            var result = new JsonObject
58	            {
59	                ["ok"] = true,
60	                ["stamped"] = CountStamped(workstate),
61	                ["missingFiles"] = CountMissing(workstate),
62	                ["runtimeIndex"] = "docs/context/RUNTIME-INDEX.md",
63	                ["handoff"] = "docs/handoff/HANDOFF.md",
64	            };
65	            Console.WriteLine(result.ToJsonString(WriteOptions));
66	            return 0;
67	        }
68	        catch (Exception ex)
69	        {
70	            Console.Error.WriteLine($"{{\"error\":\"projection failed: {ex.Message}\"}}");
71	            return 2;
72	        }
73	    }
74	
75	    // changedFiles 각 항목에 sha256을 계산해 채운다. 파일이 없으면 sha256=null, missing=true.
76	    private static void StampHashes(string root, JsonObject workstate)
77	    {
78	        var changed = workstate["changedFiles"] as JsonArray;
79	        if (changed is null) return;
80	
81	        foreach (var node in changed.OfType<JsonObject>())
82	        {
83	            var path = node["path"]?.ToString() ?? "";
84	            if (string.IsNullOrWhiteSpace(path)) continue;
85	            if (SelfExcluded.Contains(path)) continue;
86	
87	            var fullPath = Path.GetFullPath(Path.Combine(root, path));
88	            if (!File.Exists(fullPath))
89	            {
90	                node["sha256"] = null;
91	                node["missing"] = true;
92	            }
93	            else
94	            {
95	                var hash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(fullPath))).ToLowerInvariant();
96	                node["sha256"] = hash;
97	                if (node["missing"] is not null)
98	                    node.Remove("missing");
99	            }
100	        }
101	    }
102	
103	    // tmp 파일을 먼저 쓴 뒤 원자적으로 교체해 부분 쓰기를 방지한다.
104	    private static void WriteAtomically(string targetPath, string content)
105	    {
106	        var tmpPath = targetPath + ".tmp";
107	        File.WriteAllText(tmpPath, content, new UTF8Encoding(false));
108	        File.Move(tmpPath, targetPath, overwrite: true);
109	    }
110	
111	    // 해시가 채워진 항목 수를 반환한다.
112	    private static int CountStamped(JsonObject workstate)
113	    {
114	        var changed = workstate["changedFiles"] as JsonArray;
115	        return changed?.OfType<JsonObject>().Count(o => o["sha256"] is not null && o["sha256"]?.ToString() != "") ?? 0;
116	    }
117	
118	    // sha256=null(파일 없음)인 항목 수를 반환한다.
119	    private static int CountMissing(JsonObject workstate)
120	    {
121	        var changed = workstate["changedFiles"] as JsonArray;
122	        return changed?.OfType<JsonObject>().Count(o => o["missing"]?.GetValue<bool>() == true) ?? 0;
123	    }
124	
125	    // RUNTIME-INDEX.md 내용을 생성한다(L0 최소 상태, 20줄 이내). Phase·WP·DI·status·blockers·nextActions 필수.
126	    private static string GenerateRuntimeIndex(JsonObject workstate)
127	    {
128	        var sb = new StringBuilder();
129	        sb.AppendLine(GeneratedWarning);
130	        sb.AppendLine();
131	        sb.AppendLine("# RUNTIME-INDEX — 현재 실행 위치 (L0)");
132	        sb.AppendLine();
133	
134	        var phaseId = workstate["phaseId"]?.ToString() ?? "—";
135	        var wpId = workstate["wpId"]?.ToString() ?? "—";
136	        var diId = workstate["diId"]?.ToString() ?? "—";
137	        var status = workstate["status"]?.ToString() ?? "—";
138	        var updatedAt = workstate["updatedAt"]?.ToString() ?? "—";
139	        var blockers = workstate["blockers"] as JsonArray;
140	        var nextActions = workstate["nextActions"] as JsonArray;
141	
142	        sb.AppendLine($"| 항목 | 값 |");
143	        sb.AppendLine($"| --- | --- |");
144	        sb.AppendLine($"| phaseId | {phaseId} |");
145	        sb.AppendLine($"| wpId | {wpId} |");
146	        sb.AppendLine($"| diId | {diId} |");
147	        sb.AppendLine($"| status | {status} |");
148	        sb.AppendLine($"| blockers | {InlineList(blockers)} |");
149	        sb.AppendLine($"| nextActions | {InlineList(nextActions)} |");
150	        sb.AppendLine($"| updatedAt | {updatedAt} |");
151	
152	        return sb.ToString();
153	    }
154	
155	    // JsonArray 요소를 세미콜론으로 이어 한 줄로 만든다. 비어 있으면 "—" 반환.
156	    private static string InlineList(JsonArray? arr)
157	    {
158	        if (arr is null || arr.Count == 0) return "—";
159	        return string.Join("; ", arr.OfType<JsonValue>().Select(v => v.ToString()));
160	    }
161	
162	    // HANDOFF.md 내용을 생성한다(사람용 인수인계 Projection).
163	    private static string GenerateHandoff(string root, JsonObject workstate)
164	    {
165	        var sb = new StringBuilder();
166	        sb.AppendLine(GeneratedWarning);
167	        sb.AppendLine();
168	        sb.AppendLine("# HANDOFF — 인수인계 문서");
169	        sb.AppendLine();
170	        AppendHandoffHeader(sb, workstate);
171	        AppendHandoffChangedFiles(sb, workstate);
172	        AppendHandoffHistoryAndTests(sb, workstate);
173	        AppendHandoffFooter(sb, workstate);
174	        return sb.ToString();
175	    }
176	
177	    // 현재 위치·blockers[] 절을 추가한다.
178	    private static void AppendHandoffHeader(StringBuilder sb, JsonObject workstate)
179	    {
180	        var diId = workstate["diId"]?.ToString() ?? "—";
181	        var status = workstate["status"]?.ToString() ?? "—";
182	        var phaseId = workstate["phaseId"]?.ToString() ?? "—";
183	        var updatedAt = workstate["updatedAt"]?.ToString() ?? "—";
184	        var updatedBy = workstate["updatedBy"]?.ToString() ?? "—";
185	        var blockers = workstate["blockers"] as JsonArray;
186	
187	        sb.AppendLine("## 현재 위치");
188	        sb.AppendLine($"- **diId**: {diId}  **phaseId**: {phaseId}  **status**: {status}");
189	        sb.AppendLine($"- **갱신자**: {updatedBy}  **갱신일**: {updatedAt}");
190	        sb.AppendLine();
191	
192	        if (blockers is { Count: > 0 })
193	        {
194	            sb.AppendLine("## 블로커");
195	            foreach (var b in blockers.OfType<JsonValue>())
196	                sb.AppendLine($"- {b}");
197	            sb.AppendLine();
198	        }
199	    }
200	
201	    // 변경 파일 목록과 해시 태그를 추가한다.
202	    private static void AppendHandoffChangedFiles(StringBuilder sb, JsonObject workstate)
203	    {
204	        var changed = workstate["changedFiles"] as JsonArray;
205	        sb.AppendLine($"## 변경 파일 ({changed?.Count ?? 0}개)");
206	        if (changed is null)
207	        {
208	            sb.AppendLine();
209	            return;
210	        }
211	        foreach (var node in changed.OfType<JsonObject>())
212	        {
213	            var path = node["path"]?.ToString() ?? "—";
214	            var sha = node["sha256"]?.ToString();
215	            var missing = node["missing"]?.GetValue<bool>() == true;
216	            var note = node["note"]?.ToString();
217	
218	            string hashTag;
219	            if (missing) hashTag = "MISSING";
220	            else if (string.IsNullOrEmpty(sha)) hashTag = "NO-HASH";
221	            else hashTag = sha[..Math.Min(16, sha.Length)] + "…";
222	
223	            var noteInfo = note is not null ? $" — {note}" : "";
224	            sb.AppendLine($"- `{path}` [{hashTag}]{noteInfo}");
225	        }
226	        sb.AppendLine();
227	    }
228	
229	    // 완료 이력과 검증 결과 절을 추가한다.
230	    private static void AppendHandoffHistoryAndTests(StringBuilder sb, JsonObject workstate)
231	    {
232	        var history = workstate["history"] as JsonArray;
233	        if (history is { Count: > 0 })
234	        {
235	            sb.AppendLine("## 완료 이력");
236	            foreach (var item in history.OfType<JsonObject>())
237	            {
238	                var hId = item["diId"]?.ToString() ?? "—";
239	                var files = item["changedFiles"] as JsonArray;
240	                sb.AppendLine($"- **{hId}**: {files?.Count ?? 0}개 파일");
241	            }
242	            sb.AppendLine();
243	        }
244	
245	        var tests = workstate["tests"] as JsonObject;
246	        if (tests is not null)
247	        {
248	            sb.AppendLine("## 검증 결과");
249	            sb.AppendLine($"- behaviorEqual: {tests["behaviorEqual"]}");
250	            sb.AppendLine($"- buildVerifyVerdict: {tests["buildVerifyVerdict"]}");
251	            sb.AppendLine($"- measureViolationsAfter: {tests["measureViolationsAfter"]}");
252	            sb.AppendLine();
253	        }
254	    }
255	
256	    // 다음 작업·재개 전 검증·노트 절을 추가한다.
257	    private static void AppendHandoffFooter(StringBuilder sb, JsonObject workstate)
258	    {
259	        var nextActions = workstate["nextActions"] as JsonArray;
260	        if (nextActions is { Count: > 0 })
261	        {
262	            sb.AppendLine("## 다음 작업");
263	            foreach (var action in nextActions.OfType<JsonValue>())
264	                sb.AppendLine($"- {action}");
265	            sb.AppendLine();
266	        }
267	
268	        sb.AppendLine("## 재개 전 검증");
269	        sb.AppendLine("```bash");
270	        sb.AppendLine("dotnet run --project server -c Release -- handoff-integrity");
271	        sb.AppendLine("dotnet run --project server -c Release -- measure dev-pack");
272	        sb.AppendLine("dotnet run --project server -c Release -- build-verify");
273	        sb.AppendLine("dotnet run --project server -c Release -- verify-behavior");
274	        sb.AppendLine("```");
275	
276	        var notes = workstate["notes"]?.ToString();
277	        if (!string.IsNullOrWhiteSpace(notes))
278	        {
279	            sb.AppendLine();
280	            sb.AppendLine("## 노트");
281	            sb.AppendLine(notes);
282	        }
283	    }
284	}
