            sb.AppendLine($"- `{path}` [{hashTag}]{noteInfo}");
        }
        sb.AppendLine();
    }

    // 완료 이력과 검증 결과 절을 추가한다.
    private static void AppendHandoffHistoryAndTests(StringBuilder sb, JsonObject workstate)
    {
        var history = workstate["history"] as JsonArray;
        if (history is { Count: > 0 })
        {
            sb.AppendLine("## 완료 이력");
            foreach (var item in history.OfType<JsonObject>())
