        return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";

    if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
        return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";

